// fanned triple bolt (split shot) — three energy darts splaying from one toxic
// core, neon-green tracers.
defineIcon('ability_g_splitshot', P.greenD, (p) => {
  p.glow(4, 8, 5, P.toxic, 0.25, 3);

  const spread = [-3, 0, 3]; // vertical fan offset of each tip
  for (let i = 0; i < 3; i++) {
    const ty = 8 + spread[i];
    // glowing trail (dark core under bright tracer)
    p.line(3, 8, 12, ty, darken(P.greenD, 0.1));
    p.line(3, 8, 12, ty, P.green);
    p.line(4, 8, 12, ty, P.greenL);
    // arrowhead at the splayed tip
    p.line(12, ty, 10, ty - 1, P.toxic); p.line(12, ty, 10, ty + 1, P.toxic);
    p.px(12, ty, P.white);
  }

  // shared launch core
  p.glow(3, 8, 2.2, P.toxic, 0.6, 3);
  p.ellipse(3, 8, 1.6, 1.6, P.greenL);
  p.px(3, 8, P.white); p.px(2, 7, P.glint);
  p.star4(3, 8, 2, P.toxic);
});

// branching lightning (chain) — forked electric arc, cyan-hot core with neon
// glow and crackle nodes.
defineIcon('ability_g_chainlight', P.blueD, (p) => {
  // ambient electric haze
  p.glow(7, 8, 7, P.neon, 0.2, 3);

  // main bolt: glow underlay then bright core
  const seg = (x0, y0, x1, y1) => {
    p.line(x0, y0, x1, y1, withAlpha(P.neon, 0.5)); // halo
    p.line(x0, y0, x1, y1, P.ice);                  // core
  };
  seg(8, 2, 5, 7); seg(5, 7, 9, 8); seg(9, 8, 6, 13);
  // branches
  seg(5, 7, 2, 10); seg(9, 8, 13, 11);

  // white-hot inner spine on the main path
  p.px(8, 2, P.white); p.px(6, 5, P.white); p.px(7, 8, P.white); p.px(7, 11, P.white);

  // crackle nodes / endpoints
  p.glow(8, 2, 2, P.neonL, 0.6, 3); p.px(8, 2, P.glint);
  p.px(2, 10, P.white); p.glow(2, 10, 1.6, P.neonL, 0.6, 2);
  p.px(13, 11, P.white); p.glow(13, 11, 1.6, P.neonL, 0.6, 2);
  p.px(6, 13, P.neonL);
  p.star4(8, 2, 2, P.glint);
  p.sparkle(11, 9, P.neonL, 1);
});

