  p.ellipse(8, 10, 3.4, 3.4, P.gray1);
  p.ellipse(7, 9, 1.6, 1.6, P.gray3);            // specular sheen
  p.px(6, 8, P.gray4); p.px(6, 8, P.white);

  // neck + fuse climbing to the top-right
  p.rect(7, 4, 2, 2, P.gray2);
  p.line(9, 5, 11, 2, P.wood); p.px(10, 4, P.woodL);

